									<div class="form-group">
										<label :for="'conn-map-author-' + index">{{ t('intravox', 'Author field') }}</label>
										<input :id="'conn-map-author-' + index" v-model="conn.responseMapping.author" type="text" :placeholder="t('intravox', 'author (optional)')" />
