	margin-top: 16px;
}

.message.success {
	background-color: var(--color-success-hover);
	color: var(--color-success-text);
}

.message.error {
	background-color: var(--color-error-hover);
	color: var(--color-error-text);
}

.icon-loading-small {
	display: inline-block;
	width: 16px;
	height: 16px;
	border: 2px solid transparent;
	border-top-color: currentColor;
	border-radius: 50%;
	animation: spin 0.8s linear infinite;
}

@keyframes spin {
	to { transform: rotate(360deg); }
}

.icon-download {
	display: inline-block;
	width: 16px;
	height: 16px;
}

.reinstall-dialog-content {
	padding: 8px 0;
}

.reinstall-warning {
	margin-top: 12px;
	color: var(--color-text-maxcontrast);
}

/* Clean Start dialog */
.clean-start-dialog-content {
	padding: 8px 0;
}

.clean-start-info {
	margin: 12px 0 8px 0;
	color: var(--color-main-text);
}

.deletion-list {
	margin: 8px 0 16px 20px;
	padding: 0;
	color: var(--color-text-maxcontrast);
}

.deletion-list li {
	margin-bottom: 4px;
}

.clean-start-result {
	margin: 16px 0 12px 0;
	color: var(--color-main-text);
	font-weight: 500;
}

/* Action cell with multiple buttons */
.action-cell {
	display: flex;
	gap: 8px;
	align-items: center;
}

/* Video domains section */
.settings-section + .settings-section {
	margin-top: 40px;
	padding-top: 20px;
	border-top: 1px solid var(--color-border);
}

/* Services Grid - 2 columns */
.services-grid {
	display: grid;
	grid-template-columns: repeat(2, 1fr);
	gap: 20px;
	margin-bottom: 24px;
}

@media (max-width: 768px) {
	.tab-navigation {
		flex-direction: column;
		gap: 0;
	}

	.tab-button {
		width: 100%;
		justify-content: flex-start;
		border-bottom: none;
		border-left: 2px solid transparent;
	}

	.tab-button.active {
		border-bottom: none;
		border-left-color: var(--color-primary);
	}

	.services-grid {
		grid-template-columns: 1fr;
	}
}

/* Custom servers category spans full width */
.service-category.custom {
	grid-column: 1 / -1;
}

.service-category {
	/* No margin needed - grid handles spacing */
}

.category-header {
	display: flex;
	align-items: center;
	gap: 8px;
	margin: 0 0 12px 0;
	padding: 8px 12px;
	font-size: 14px;
	font-weight: 600;
	border-radius: var(--border-radius);
}

.category-header.privacy {
	background-color: var(--color-success-hover);
	color: var(--color-success-text);
}

.category-header.tracking {
	background-color: var(--color-warning-hover);
	color: var(--color-warning-text);
}

.category-header.custom {
	background-color: var(--color-background-dark);
	color: var(--color-main-text);
}

.category-icon {
	font-size: 16px;
}

.service-list {
	display: flex;
	flex-direction: column;
	gap: 4px;
}

.service-item {
	padding: 8px 12px;
	background: var(--color-background-hover);
	border-radius: var(--border-radius);
	border-left: 3px solid transparent;
	transition: border-color 0.15s ease;
}

.service-item.enabled {
	border-left-color: var(--color-success);
	background: var(--color-background-dark);
}

.service-item.tracking-warning.enabled {
	border-left-color: var(--color-warning);
}

/* Custom domain items */
.service-item.custom-item {
	display: flex;
	align-items: center;
	justify-content: space-between;
}

.custom-domain-info {
	display: flex;
	flex-direction: column;
	gap: 4px;
	flex: 1;
}

/* Risk badges */
.risk-badge {
	display: inline-flex;
	align-items: center;
	gap: 4px;
	font-size: 12px;
	font-weight: 500;
	padding: 2px 8px;
	border-radius: 10px;
	width: fit-content;
}

.risk-badge.good {
	background-color: var(--color-success-hover);
	color: var(--color-success-text);
}

.risk-badge.warning {
	background-color: var(--color-warning-hover);
	color: var(--color-warning-text);
}

.risk-badge.danger {
	background-color: var(--color-error-hover);
	color: var(--color-error-text);
}

.risk-badge.unknown {
	background-color: var(--color-background-dark);
	color: var(--color-text-maxcontrast);
}

.service-item :deep(.checkbox-radio-switch) {
	width: 100%;
}

.service-item :deep(.checkbox-radio-switch__content) {
	flex: 1;
}

.service-info {
	display: flex;
	flex-direction: column;
	gap: 2px;
}

.service-name {
	display: flex;
	align-items: center;
	gap: 6px;
	font-weight: 500;
	color: var(--color-main-text);
}

/* External link styling for services */
.service-link {
	color: var(--color-text-maxcontrast);
	opacity: 0.6;
	transition: opacity 0.2s, color 0.2s;
	vertical-align: middle;
	text-decoration: none;
}

.service-link:hover {
	opacity: 1;
	color: var(--color-primary);
}

.service-item:hover .service-link {
	opacity: 0.8;
}

.custom-domain-link {
	display: inline-flex;
	align-items: center;
	gap: 4px;
	color: var(--color-main-text);
	text-decoration: none;
	transition: color 0.2s;
}

.custom-domain-link:hover {
	color: var(--color-primary);
}

.custom-domain-link :deep(svg) {
	opacity: 0.5;
	transition: opacity 0.2s;
}

.custom-domain-link:hover :deep(svg) {
	opacity: 1;
}

.protocol-badge {
	display: inline-block;
	font-size: 10px;
	font-weight: 600;
	padding: 2px 6px;
	border-radius: 4px;
	background-color: var(--color-success);
	color: white;
	text-transform: uppercase;
	letter-spacing: 0.5px;
}

.service-domain {
	font-size: 12px;
	color: var(--color-text-maxcontrast);
	font-family: var(--font-monospace, monospace);
}

/* Add domain row */
.add-domain-row {
	display: flex;
	align-items: center;
	gap: 8px;
}

.domain-input {
	flex: 1;
	padding: 8px 12px;
	border: 1px solid var(--color-border);
	border-radius: var(--border-radius);
	background: var(--color-main-background);
	color: var(--color-main-text);
	font-size: 14px;
}

.domain-input:focus {
	border-color: var(--color-primary-element);
	outline: none;
}

.custom-server-hint {
	margin: 8px 0 0 0;
	font-size: 12px;
	color: var(--color-text-maxcontrast);
	font-style: italic;
}

/* Warnings */
.domain-warnings {
	margin: 16px 0;
}

.domain-warnings ul {
	margin: 8px 0 0 0;
	padding-left: 20px;
}

.domain-warnings li {
	margin-bottom: 4px;
}

/* Save section */
.save-section {
	margin-top: 24px;
	padding-top: 16px;
	border-top: 1px solid var(--color-border);
}

/* Section headers */
.settings-section h3 {
	font-size: 14px;
	font-weight: 600;
	margin: 0 0 12px 0;
}

/* Engagement tab styles */
.engagement-group {
	margin-bottom: 24px;
	padding: 16px;
	background: var(--color-background-hover);
	border-radius: var(--border-radius-large);
}

.engagement-group-header {
	display: flex;
	align-items: center;
	gap: 8px;
	margin: 0 0 16px 0;
	padding-bottom: 8px;
	border-bottom: 1px solid var(--color-border);
	font-size: 15px;
	font-weight: 600;
}

.engagement-icon {
	font-size: 18px;
}

.engagement-option {
	padding: 8px 0;
}

.engagement-option.sub-option {
	margin-left: 24px;
	padding-left: 16px;
	border-left: 2px solid var(--color-border);
}

.option-info {
	display: flex;
	flex-direction: column;
	gap: 2px;
}

.option-label {
	font-weight: 500;
	color: var(--color-main-text);
}

.option-desc {
	font-size: 12px;
	color: var(--color-text-maxcontrast);
}

/* Export tab styles */
.export-options {
	display: flex;
	flex-direction: column;
	gap: 16px;
	max-width: 400px;
}

.export-row {
	display: flex;
	flex-direction: column;
	gap: 8px;
}

.export-progress {
	margin-top: 16px;
}

.progress-text {
	margin-top: 8px;
	color: var(--color-text-lighter);
	font-size: 14px;
	text-align: center;
}

.export-result {
	margin-top: 16px;
}

.export-label {
	font-weight: 500;
	color: var(--color-main-text);
}

.export-select {
	padding: 8px 12px;
	border: 1px solid var(--color-border);
	border-radius: var(--border-radius);
	background: var(--color-main-background);
	color: var(--color-main-text);
	font-size: 14px;
	cursor: pointer;
}

.export-select:focus {
	border-color: var(--color-primary-element);
	outline: none;
}

.export-format-options {
	display: flex;
	flex-direction: column;
	gap: 4px;
}

/* Import section styles */
.import-section {
	margin-top: 32px;
	padding-top: 24px;
	border-top: 1px solid var(--color-border);
}

.import-options {
	display: flex;
	flex-direction: column;
	gap: 16px;
	max-width: 500px;
}

.import-row {
	display: flex;
	flex-direction: column;
	gap: 8px;
}

.import-label {
	font-weight: 500;
	color: var(--color-main-text);
}

.import-file-input {
	padding: 8px 12px;
	border: 1px solid var(--color-border);
	border-radius: var(--border-radius);
	background: var(--color-main-background);
	color: var(--color-main-text);
	font-size: 14px;
	cursor: pointer;
}

.import-file-input:focus {
	border-color: var(--color-primary-element);
	outline: none;
}

.import-filename {
	font-size: 13px;
	color: var(--color-text-maxcontrast);
	font-style: italic;
}

.import-progress {
	margin-top: 16px;
}

.import-progress .note-card,
.export-progress .note-card {
	margin-bottom: 16px;
}

.import-progress p,
.export-progress p {
	margin: 4px 0;
}

.import-result {
	margin-top: 16px;
}

/* Sub-tab navigation */
.sub-tab-navigation {
	display: flex;
	gap: 8px;
	margin-bottom: 30px;
	border-bottom: 2px solid var(--color-border);
	padding-bottom: 0;
}

.sub-tab-button {
	display: flex;
	align-items: center;
	gap: 8px;
	padding: 12px 24px;
	border: none;
	background: none;
	color: var(--color-text-lighter);
	cursor: pointer;
	transition: all 0.2s ease;
	border-bottom: 3px solid transparent;
	margin-bottom: -2px; /* Overlap parent border */
	font-size: 14px;
	font-weight: 500;
}

.sub-tab-button:hover {
	color: var(--color-main-text);
	background: var(--color-background-hover);
}

.sub-tab-button.active {
	color: var(--color-primary);
	border-bottom-color: var(--color-primary);
	background: var(--color-primary-element-light);
}

.sub-tab-button .material-design-icon {
	display: flex;
	align-items: center;
}

/* Publication Settings */
.publication-settings {
	margin-top: 20px;
}

.settings-info {
	color: var(--color-text-maxcontrast);
	margin-bottom: 24px;
	line-height: 1.5;
}

.setting-row {
	margin-bottom: 24px;
}

.setting-label {
	display: block;
	font-weight: 500;
	margin-bottom: 8px;
	color: var(--color-main-text);
}

.setting-input {
	width: 100%;
	max-width: 400px;
	padding: 8px 12px;
	border: 1px solid var(--color-border);
	border-radius: 4px;
	font-size: 14px;
	background: var(--color-main-background);
	color: var(--color-main-text);
}

.setting-input:focus {
	border-color: var(--color-primary-element);
	outline: none;
	box-shadow: 0 0 0 2px var(--color-primary-element-light);
}

.setting-input::placeholder {
	color: var(--color-text-maxcontrast);
}

.setting-hint {
	margin-top: 6px;
	font-size: 13px;
	color: var(--color-text-maxcontrast);
}

.setting-select {
	width: 100%;
	max-width: 400px;
	padding: 8px 12px;
	border: 1px solid var(--color-border);
	border-radius: 4px;
	font-size: 14px;
	background: var(--color-main-background);
	color: var(--color-main-text);
	cursor: pointer;
}

.setting-select:focus {
	border-color: var(--color-primary-element);
	outline: none;
	box-shadow: 0 0 0 2px var(--color-primary-element-light);
}

.loading-fields {
	display: flex;
	align-items: center;
	gap: 8px;
	padding: 16px;
	color: var(--color-text-maxcontrast);
}

/* Sharing tab styles */
.shares-loading {
	display: flex;
	align-items: center;
	gap: 8px;
	padding: 16px 0;
	color: var(--color-text-maxcontrast);
}

.shares-table {
	width: 100%;
	border-collapse: collapse;
	margin-bottom: 20px;
}

.shares-table th,
.shares-table td {
	padding: 12px;
	text-align: left;
	border-bottom: 1px solid var(--color-border);
}

.shares-table th {
	font-weight: bold;
	color: var(--color-text-maxcontrast);
}

.share-expired {
	opacity: 0.6;
}

.scope-cell {
	display: flex;
	align-items: center;
	gap: 6px;
}

.scope-label {
	font-weight: 500;
}

.scope-badge {
	display: inline-block;
	padding: 2px 6px;
	border-radius: 4px;
	font-size: 0.75em;
	font-weight: 600;
}

.language-badge {
	background-color: var(--color-primary-element-light);
	color: var(--color-primary-element);
}

.expired-badge {
	background-color: var(--color-error);
	color: white;
}

.path-cell {
	font-family: monospace;
	font-size: 0.9em;
	color: var(--color-text-maxcontrast);
}

.date-cell {
	white-space: nowrap;
}

.expired-text {
	color: var(--color-error);
}

.share-files-link {
	display: inline-flex;
	align-items: center;
	gap: 4px;
	font-size: 13px;
	color: var(--color-primary-element);
	text-decoration: none;
	padding: 4px 8px;
	border-radius: var(--border-radius);
	transition: background-color 0.1s ease;
}

.share-files-link:hover {
	background-color: var(--color-background-hover);
}

/* Maintenance Tab Styles */
.scan-section {
	margin: 20px 0;
}

.no-orphaned {
	margin-top: 20px;
}

.orphaned-table {
	width: 100%;
	border-collapse: collapse;
	margin-top: 20px;
}

.orphaned-table th,
.orphaned-table td {
	padding: 12px;
	text-align: left;
	border-bottom: 1px solid var(--color-border);
}

.orphaned-table th {
	font-weight: bold;
	color: var(--color-text-maxcontrast);
}

.orphaned-table .id-cell {
	font-family: monospace;
	font-weight: bold;
}

.orphaned-table .content-badge.intravox {
	background-color: var(--color-primary-element-light);
	color: var(--color-primary-element-text);
	padding: 4px 8px;
	border-radius: 4px;
	font-size: 0.85em;
}

.orphaned-table .content-badge.unknown {
	background-color: var(--color-background-hover);
	color: var(--color-text-maxcontrast);
	padding: 4px 8px;
	border-radius: 4px;
	font-size: 0.85em;
}

.orphaned-table .page-count {
	margin-left: 4px;
	opacity: 0.8;
}

.orphaned-table .action-cell {
	display: flex;
	gap: 8px;
}

/* Migrate dialog */
.migrate-dialog-content {
	padding: 10px 0;
}

.migrate-option {
	margin: 16px 0;
}

.migrate-option label {
	display: block;
	font-weight: bold;
	margin-bottom: 8px;
}

.migrate-select {
	width: 100%;
	padding: 8px;
	border: 1px solid var(--color-border);
	border-radius: var(--border-radius);
	background-color: var(--color-main-background);
}

/* Cleanup dialog */
.cleanup-dialog-content {
	padding: 10px 0;
}

.cleanup-dialog-content ul {
	margin: 12px 0;
	padding-left: 20px;
}

.cleanup-dialog-content li {
	margin: 4px 0;
}

/* Connection cards */
.connection-card {
	border: 1px solid var(--color-border);
	border-radius: var(--border-radius-large);
	margin-bottom: 8px;
	background: var(--color-main-background);
	overflow: hidden;
}

.connection-card--expanded {
	background: var(--color-background-hover);
}

.connection-card--inactive {
	opacity: 0.6;
}

.connection-card--inactive .connection-name {
	text-decoration: line-through;
}

.connection-header {
	display: flex;
	align-items: center;
	gap: 10px;
	padding: 10px 12px;
	cursor: pointer;
	user-select: none;
}

.connection-header:hover {
	background: var(--color-background-hover);
}

.connection-badge.configured {
	color: var(--color-success-text, #2d7a3a);
	background: var(--color-success-element-light, color-mix(in srgb, var(--color-success) 15%, transparent));
}

.connection-badge.not-configured {
	color: var(--color-warning-text, #945a00);
	background: var(--color-warning-element-light, color-mix(in srgb, var(--color-warning) 15%, transparent));
}


.connection-name {
	font-weight: 600;
	font-size: 14px;
	color: var(--color-main-text);
	flex: 1;
	min-width: 0;
	overflow: hidden;
	text-overflow: ellipsis;
	white-space: nowrap;
}

.connection-type {
	font-size: 12px;
	color: var(--color-text-maxcontrast);
	flex-shrink: 0;
}

.connection-badge {
	font-size: 11px;
	font-weight: 500;
	flex-shrink: 0;
	padding: 2px 8px;
	border-radius: var(--border-radius-pill, 12px);
	color: var(--color-text-maxcontrast);
	white-space: nowrap;
}

.connection-chevron {
	font-size: 12px;
	color: var(--color-text-maxcontrast);
	flex-shrink: 0;
	width: 16px;
	text-align: center;
}

.connection-remove {
	background: none;
	border: none;
	color: var(--color-text-maxcontrast);
	cursor: pointer;
	font-size: 20px;
	line-height: 1;
	padding: 0 4px;
	border-radius: var(--border-radius);
	flex-shrink: 0;
}

.connection-remove:hover {
	color: var(--color-error);
	background: var(--color-background-hover);
}

.connection-body {
	padding: 0 16px 16px;
}

.connection-test {
	display: flex;
	align-items: center;
	gap: 12px;
	padding: 12px 0 4px;
	border-top: 1px solid var(--color-border);
	margin-top: 12px;
}

.connection-test-result {
	margin-top: 8px;
}

.feed-connection-actions-spacer {
	flex: 1;
}

.import-preview-list {
	margin: 8px 0 12px;
	padding-left: 20px;
}

.import-preview-list li {
	padding: 4px 0;
}

.import-preview-list .is-duplicate {
	opacity: 0.5;
	text-decoration: line-through;
}

.import-duplicate-badge {
	font-size: 11px;
	color: var(--color-text-maxcontrast);
	font-style: italic;
	margin-left: 6px;
}

.advanced-toggle {
	display: inline-block;
	padding: 8px 0;
	margin-top: 8px;
	background: none;
	border: none;
	cursor: pointer;
	color: var(--color-primary-element);
	font-size: 13px;
	font-weight: 500;
}

.advanced-toggle:hover {
	text-decoration: underline;
}

.advanced-fields {
	margin-top: 4px;
}

.clean-start-confirm {
	margin-top: 16px;
	display: flex;
	flex-direction: column;
	gap: 6px;
}

.clean-start-confirm-input {
	max-width: 200px;
	padding: 6px 10px;
	border: 2px solid var(--color-error);
	border-radius: var(--border-radius);
	font-size: 14px;
	font-weight: 600;
	letter-spacing: 2px;
	text-transform: uppercase;
}

.connection-fields .form-group {
	display: flex;
	flex-direction: column;
	gap: 4px;
}

.connection-fields label {
	font-size: 13px;
	font-weight: 600;
}

.fields-grid {
	display: grid;
	grid-template-columns: 1fr 1fr;
	gap: 12px;
}

.fields-grid .full-width {
	grid-column: 1 / -1;
}

.field-section {
	border-top: 1px solid var(--color-border);
	padding-top: 12px;
	margin-top: 12px;
	display: flex;
	flex-direction: column;
	gap: 8px;
}

.field-section-title {
	font-size: 14px;
	font-weight: 600;
	color: var(--color-main-text);
	margin-bottom: 4px;
}

.custom-header-row {
	display: flex;
	gap: 8px;
	align-items: center;
	margin-top: 4px;
}

.custom-header-row .header-key {
	flex: 2;
}

.custom-header-row .header-value {
	flex: 3;
}

.custom-header-row .header-remove {
	background: none;
	border: none;
	color: var(--color-text-maxcontrast);
	cursor: pointer;
	font-size: 18px;
	padding: 4px 8px;
	border-radius: var(--border-radius);
}

.custom-header-row .header-remove:hover {
	background: var(--color-error);
	color: var(--color-primary-element-text);
}

.connection-fields input,
.connection-fields select {
	width: 100%;
	padding: 8px 12px;
	border: 1px solid var(--color-border);
	border-radius: var(--border-radius);
	background: var(--color-main-background);
	color: var(--color-main-text);
	font-size: 14px;
	box-sizing: border-box;
}

.connection-fields input[type="password"],
.connection-fields input[type="url"],
.connection-fields input[type="text"] {
	min-width: 0;
}

.connection-fields .checkbox-label {
	display: flex;
	align-items: center;
	gap: 8px;
	font-weight: normal;
	cursor: pointer;
